mapper.select:
SELECT a.id, a.title, a.content, a.publisher, a.publish_time AS publishTime, a.is_deleted AS isDeleted, a.announcement_type_id AS announcementTypeId, at.type_name AS announcementTypeName, at.priority FROM school_backend_manage.announcement a LEFT JOIN school_backend_manage.announcement_type at ON a.announcement_type_id = at.id WHERE a.is_deleted = 0
AND at.priority = #{priority}
AND a.title LIKE CONCAT('%', #{searchKeyword}, '%')
ORDER BY at.priority DESC, a.publish_time DESC LIMIT #{offset}, #{limit}

SELECT COUNT(*) FROM school_backend_manage.announcement a LEFT JOIN school_backend_manage.announcement_type at ON a.announcement_type_id = at.id WHERE a.is_deleted = 0
AND at.priority = #{priority}
AND a.title LIKE CONCAT('%', #{searchKeyword}, '%')

SELECT *
FROM school_backend_manage.repair_application
WHERE user_no = #{userNo}
AND is_deleted = 0

    AND status = #{status}

ORDER BY create_time DESC

SELECT u.user_no AS userNo, u.username, u.gender, u.phone, u.email
FROM user u
         INNER JOIN student_dormitory_info sdi ON u.user_no = sdi.user_no
WHERE sdi.building_id = #{buildingId}
  AND sdi.dormitory_number = #{dormitoryNumber}
  AND u.user_no != #{currentUserNo}
